window.ETS_LC4 = {"q12": [{"n": 1, "part": 1, "q": "", "qko": "", "opts": ["She's crossing a busy street.", "She's removing her eyeglasses.", "She's standing next to a bin.", "She's getting into a taxicab."], "optko": ["여자가 분주한 거리를 건너고 있다.", "여자가 안경을 벗고 있다.", "여자가 쓰레기통 옆에 서 있다.", "여자가 택시에 타고 있다."], "ans": 2, "audio": "Test_04-01.mp3", "img": "ets_t4_q1.jpg"}, {"n": 2, "part": 1, "q": "", "qko": "", "opts": ["Some trucks have stopped at a traffic signal.", "Some lights are being installed above a garage door.", "A garden is being planted along a fence.", "Several vehicles are parked outside a building."], "optko": ["트럭들이 교통 신호등 앞에 정차해 있다.", "전등들이 차고 문 위에 설치되고 있다.", "정원에 울타리를 따라 식물이 심어지고 있다.", "여러 대의 차량들이 건물 밖에 주차되어 있다."], "ans": 3, "audio": "Test_04-02.mp3", "img": "ets_t4_q2.jpg"}, {"n": 3, "part": 1, "q": "", "qko": "", "opts": ["A woman is following a man down a corridor.", "A woman is putting together some cardboard boxes.", "A man is emptying a large container.", "A man is climbing up a ladder."], "optko": ["여자가 복도에서 남자를 따라가고 있다.", "여자가 판지 상자들을 조립하고 있다.", "남자가 대형 용기를 비우고 있다.", "남자가 사다리 위로 올라가고 있다."], "ans": 0, "audio": "Test_04-03.mp3", "img": "ets_t4_q3.jpg"}, {"n": 4, "part": 1, "q": "", "qko": "", "opts": ["He's clearing some snow off a path.", "He's pulling a cart on a walkway.", "He's leaning over to tie his shoe.", "He's taking some items out of a basket."], "optko": ["남자가 길에서 눈을 치우고 있다.", "남자가 보도에서 카트를 끌고 있다.", "남자가 신발끈을 묶기 위해 몸을 숙이고 있다.", "남자가 바구니에서 물품을 꺼내고 있다."], "ans": 1, "audio": "Test_04-04.mp3", "img": "ets_t4_q4.jpg"}, {"n": 5, "part": 1, "q": "", "qko": "", "opts": ["One of the women is carrying a bag on her shoulder.", "One of the women is placing her luggage on a scale.", "Some suitcases have been lined up against the wall.", "Some clothes are being packed in a bag."], "optko": ["여자들 중 한 명이 어깨에 가방을 메고 있다.", "여자들 중 한 명이 짐을 저울에 올려 놓고 있다.", "여행 가방들이 벽 쪽에 줄지어 있다.", "옷들이 가방에 담기고 있다."], "ans": 0, "audio": "Test_04-05.mp3", "img": "ets_t4_q5.jpg"}, {"n": 6, "part": 1, "q": "", "qko": "", "opts": ["Some customers are drinking from coffee cups.", "Some coffee cups have been placed on a counter.", "Some aprons are hanging from hooks.", "One of the workers is wiping down a counter."], "optko": ["고객들이 커피잔에 든 것을 마시고 있다.", "커피잔들이 카운터에 놓여 있다.", "앞치마들이 고리에 걸려 있다.", "직원들 중 한 명이 카운터를 닦고 있다."], "ans": 1, "audio": "Test_04-06.mp3", "img": "ets_t4_q6.jpg"}, {"n": 7, "part": 2, "q": "Will you let me know when the catering order arrives?", "qko": "출장 요리 주문이 도착하면 알려 주실래요?", "opts": ["A reservation for two.", "The front office.", "Sure, I'll text you."], "optko": ["두 명 예약이요.", "접수처요.", "물론이죠, 문자 메시지를 보내 드리겠습니다."], "ans": 2, "audio": "Test_04-07.mp3"}, {"n": 8, "part": 2, "q": "Why is the manager being replaced?", "qko": "관리자가 왜 교체되는 건가요?", "opts": ["Let's do that.", "I prefer working with a team.", "Because she's leaving the company."], "optko": ["그렇게 합시다.", "팀과 함께 일하는 것을 선호합니다.", "그분께서 회사를 그만두시기 때문입니다."], "ans": 2, "audio": "Test_04-08.mp3"}, {"n": 9, "part": 2, "q": "Ms. Cho should close the store early on Friday.", "qko": "조 씨는 금요일에 매장을 일찍 닫아야 해요.", "opts": ["I prefer a salad.", "Cash register four.", "Yes, I agree."], "optko": ["저는 샐러드를 선호합니다.", "4번 계산대요.", "네, 동의합니다."], "ans": 2, "audio": "Test_04-09.mp3"}, {"n": 10, "part": 2, "q": "Why did you decide to become a pilot?", "qko": "왜 조종사가 되기로 결정하셨나요?", "opts": ["Is there free Internet access?", "I enjoy traveling.", "He's on vacation in Argentina."], "optko": ["무료 인터넷 접속이 가능한가요?", "여행을 즐깁니다.", "그는 아르헨티나에서 휴가 중이에요."], "ans": 1, "audio": "Test_04-10.mp3"}, {"n": 11, "part": 2, "q": "Have you always commuted by train?", "qko": "항상 기차로 통근하셨나요?", "opts": ["The training starts at two o'clock.", "I think the station is on Mulberry Avenue.", "Yes, because I don't have a car."], "optko": ["그 교육은 2시에 시작해요.", "그 역은 멀베리 가에 있는 것 같아요.", "네, 차가 없어서요."], "ans": 2, "audio": "Test_04-11.mp3"}, {"n": 12, "part": 2, "q": "When does your manager usually come in?", "qko": "매니저는 보통 언제 오시나요?", "opts": ["Early in the morning.", "No, I just left it there.", "I haven't—thanks."], "optko": ["아침 일찍이요.", "아니요, 방금 거기에 두었어요.", "그런 적 없어요. 감사합니다."], "ans": 0, "audio": "Test_04-12.mp3"}, {"n": 13, "part": 2, "q": "Isn't there a discount on this computer monitor?", "qko": "이 컴퓨터 모니터는 할인하지 않나요?", "opts": ["Yes, a ten percent discount.", "An inventory check.", "Mine is broken."], "optko": ["네, 10퍼센트 할인됩니다.", "재고 확인이요.", "제 것은 고장 났어요."], "ans": 0, "audio": "Test_04-13.mp3"}, {"n": 14, "part": 2, "q": "How is the new group of interns doing?", "qko": "신입 인턴들은 어떻게 지내고 있나요?", "opts": ["No, we have five people in total.", "I haven't heard any negative feedback at all.", "Let's pose for a group photo over there."], "optko": ["아니요, 저희는 총 다섯 명입니다.", "부정적인 의견은 전혀 듣지 못했어요.", "저쪽에서 단체 사진을 찍을 수 있게 포즈를 취합시다."], "ans": 1, "audio": "Test_04-14.mp3"}, {"n": 15, "part": 2, "q": "They're carrying those boxes to the storage room.", "qko": "그들이 그 상자들을 창고로 옮기고 있어요.", "opts": ["That's a good price.", "No, the store opens at noon today.", "I'll go with them."], "optko": ["좋은 가격이네요.", "아니요, 그 매장은 오늘 정오에 열어요.", "제가 그들과 함께 갈게요."], "ans": 2, "audio": "Test_04-15.mp3"}, {"n": 16, "part": 2, "q": "Where can I send the money?", "qko": "돈을 어디로 보내면 될까요?", "opts": ["To my bank account.", "I think that's expensive, too.", "By next Tuesday."], "optko": ["제 은행 계좌로요.", "그것도 비싼 것 같아요.", "다음 주 화요일까지요."], "ans": 0, "audio": "Test_04-16.mp3"}, {"n": 17, "part": 2, "q": "Who's coming in tomorrow to help us prepare for the grand opening?", "qko": "개장식 준비를 돕기 위해 내일 누가 오나요?", "opts": ["Rebecca and Malik.", "An online job posting.", "Some sales data."], "optko": ["레베카와 말릭이요.", "온라인 구인 광고요.", "매출 자료요."], "ans": 0, "audio": "Test_04-17.mp3"}, {"n": 18, "part": 2, "q": "How often does the bus stop at this location?", "qko": "버스가 이곳에 얼마나 자주 정차하나요?", "opts": ["I'll be visiting the office.", "About every twenty minutes.", "A city council meeting."], "optko": ["저는 그 사무실을 방문할 예정입니다.", "약 20분마다요.", "시 의회 회의요."], "ans": 1, "audio": "Test_04-18.mp3"}, {"n": 19, "part": 2, "q": "What's the candidate review process?", "qko": "지원자 평가 과정이 어떻게 되나요?", "opts": ["We review the résumés first.", "A few good reviews.", "OK—I'll just follow them."], "optko": ["우선 이력서를 검토합니다.", "몇몇 좋은 평가들이요.", "알겠어요, 그냥 따라갈게요."], "ans": 0, "audio": "Test_04-19.mp3"}, {"n": 20, "part": 2, "q": "There's coffee in the break room, right?", "qko": "휴게실에 커피 있죠, 그렇죠?", "opts": ["That shift starts at noon.", "We decided to paint this room gray.", "Yes—I just made a fresh pot."], "optko": ["그 근무는 정오에 시작합니다.", "이 방을 회색으로 칠하기로 했어요.", "네, 제가 방금 새로 끓여 놨습니다."], "ans": 2, "audio": "Test_04-20.mp3"}, {"n": 21, "part": 2, "q": "Who's going to the company picnic today?", "qko": "오늘 회사 야유회에 누가 가나요?", "opts": ["About two hours long.", "I'm leaving in a few minutes.", "A two-year maintenance contract."], "optko": ["약 두 시간이요.", "제가 몇 분 후에 출발할 거예요.", "2년 유지 관리 계약이요."], "ans": 1, "audio": "Test_04-21.mp3"}, {"n": 22, "part": 2, "q": "Will the bakery be open tomorrow?", "qko": "그 제과점이 내일 문을 열까요?", "opts": ["No, it's closed until mid-August.", "Have you checked the oven?", "The pound cake is delicious."], "optko": ["아니요, 8월 중순까지 문을 닫아요.", "오븐은 확인하셨어요?", "파운드 케이크가 맛있어요."], "ans": 0, "audio": "Test_04-22.mp3"}, {"n": 23, "part": 2, "q": "Are you installing the new software on Monday or Tuesday?", "qko": "새 소프트웨어를 월요일에 설치하실 건가요, 아니면 화요일에 하실 건가요?", "opts": ["Thanks, but they already have one.", "I'll be out of the office all week.", "It was an older model laptop."], "optko": ["감사하지만, 그분들은 이미 갖고 있어요.", "저는 이번 주 내내 사무실을 비울 거예요.", "구형 노트북이었어요."], "ans": 1, "audio": "Test_04-23.mp3"}, {"n": 24, "part": 2, "q": "Let me find a sales associate to help you.", "qko": "도와드릴 영업 사원을 찾아 드리겠습니다.", "opts": ["At the top of the list.", "My article is ready to be uploaded.", "I just found what I'm looking for."], "optko": ["목록 상단에요.", "제 기사를 업로드할 준비가 되었습니다.", "제가 찾는 것을 방금 발견했어요."], "ans": 2, "audio": "Test_04-24.mp3"}, {"n": 25, "part": 2, "q": "You're offering discounts to students, right?", "qko": "학생에게 할인을 제공하죠, 그렇죠?", "opts": ["No, that's not my wallet.", "You'll need valid identification.", "I'm doing inventory this weekend."], "optko": ["아니요, 제 지갑이 아닙니다.", "유효한 신분증이 필요할 거예요.", "이번 주말에 재고 조사를 할 거예요."], "ans": 1, "audio": "Test_04-25.mp3"}, {"n": 26, "part": 2, "q": "The sales department posted an advertisement for an assistant.", "qko": "영업부에서 업무 보조를 구하는 광고를 게시했어요.", "opts": ["I didn't know they were hiring.", "An additional charge for shipping.", "No, I haven't been there."], "optko": ["그곳에서 사람을 고용하는 줄 몰랐어요.", "추가 배송 요금이요.", "아니요, 그곳에 가 본 적 없어요."], "ans": 0, "audio": "Test_04-26.mp3"}, {"n": 27, "part": 2, "q": "Does the new accounting software work well?", "qko": "새 회계 소프트웨어가 잘 작동하나요?", "opts": ["I haven't downloaded it yet.", "We're not offering a discount.", "That was my reaction too."], "optko": ["아직 다운로드하지 않았어요.", "저희는 할인을 제공하고 있지 않아요.", "저도 그런 반응이었어요."], "ans": 0, "audio": "Test_04-27.mp3"}, {"n": 28, "part": 2, "q": "When's the finance department going to confirm our first-quarter budget?", "qko": "재무 부서에서 언제 1분기 예산을 확정할 건가요?", "opts": ["Their deadline is next week.", "Yes, I'll be there.", "In the mail room."], "optko": ["마감 기한이 다음 주예요.", "네, 그곳에 갈 거예요.", "우편실이에요."], "ans": 0, "audio": "Test_04-28.mp3"}, {"n": 29, "part": 2, "q": "Who canceled the conference call?", "qko": "누가 전화 회의를 취소했나요?", "opts": ["The upstairs conference room.", "It's been rescheduled.", "Yes, you can."], "optko": ["위층에 있는 대회의실이요.", "일정이 재조정되었습니다.", "네, 그러셔도 됩니다."], "ans": 1, "audio": "Test_04-29.mp3"}, {"n": 30, "part": 2, "q": "Can you please transfer the service to my new phone?", "qko": "새 휴대폰으로 서비스를 이전해 주실 수 있나요?", "opts": ["Let's put it in the backseat.", "At the Maple Street station.", "There is a processing fee."], "optko": ["뒷자리에 둡시다.", "메이플 가 역이에요.", "처리 수수료가 있습니다."], "ans": 2, "audio": "Test_04-30.mp3"}, {"n": 31, "part": 2, "q": "How was today's manufacturing seminar?", "qko": "오늘 있었던 제조 세미나는 어땠나요?", "opts": ["A new pair of shoes.", "We didn't get there in time.", "There's a user's manual in the drawer."], "optko": ["새 신발 한 켤레요.", "저희는 제때 도착하지 못했어요.", "서랍에 사용자 설명서가 있어요."], "ans": 1, "audio": "Test_04-31.mp3"}], "sets34": [{"start": 32, "part": 3, "intro": "", "graphic": false, "speakers": "W-Am / M-Au", "audio": "Test_04-32-34.mp3", "qs": [{"n": 32, "q": "Who most likely is the woman?", "opts": ["A landscape architect", "An interior designer", "A real estate agent", "A building inspector"], "ans": 2, "ko": "여자가 첫 대사에서 남자에게 아파트를 둘러보러 와 줘서 감사하다(Thanks for coming to tour this apartment building)고 했다. 이는 부동산 중개업자가 아파트를 보러 온 사람에게 할 수 있는 말이므로 정답은 (C)이다."}, {"n": 33, "q": "What is the man looking forward to?", "opts": ["Living in a particular area", "Walking to work", "Going on vacation", "Saving money for a house"], "ans": 0, "ko": "남자가 첫 대사에서 항상 이 동네에 살고 싶었다(I've always wanted to live in this neighborhood)고 했으므로 정답은 (A)이다. Paraphrasing: 대화의 this neighborhood → 정답의 a particular area"}, {"n": 34, "q": "What does the woman ask for?", "opts": ["Some references", "Some identification", "A signature", "A payment"], "ans": 2, "ko": "여자가 두 번째 대사에서 방명록에 서명할 것(~ would you please sign your name here in our guest book?)을 요청하고 있으므로 정답은 (C)이다. Paraphrasing: 대화의 sign your name → 정답의 A signature"}], "script": [{"sp": "W", "en": "Good morning. Thanks for coming to tour this apartment building.", "ko": "안녕하세요. 이 아파트를 둘러보러 와 주셔서 감사합니다."}, {"sp": "M", "en": "I'm glad I could visit in person. I've always wanted to live in this neighborhood—it's so beautiful. This building is brand-new, isn't it?", "ko": "직접 방문할 수 있어서 기뻐요. 항상 이 동네에 살고 싶었거든요. 너무 아름답네요. 이 건물은 신축이죠, 아닌가요?"}]}, {"start": 35, "part": 3, "intro": "", "graphic": false, "speakers": "W-Am / M-Cn", "audio": "Test_04-35-37.mp3", "qs": [{"n": 35, "q": "What most likely is the man's job?", "opts": ["Boat crew member", "Restaurant owner", "Seafood inspector", "Delivery truck driver"], "ans": 3, "ko": "여자가 첫 대사에서 남자에게 모건 지역에 해산물 배송 업무가 예정되어 있는 걸 봤다며, 왜 아직 출발하지 않았는지(I saw you have some scheduled seafood deliveries ~. Why haven't you left yet?) 묻고 있으므로 정답은 (D)이다."}, {"n": 36, "q": "Why is the woman concerned?", "opts": ["A road has been temporarily closed.", "A permit has expired.", "Traffic may cause a delay.", "Some supplies are no longer available."], "ans": 2, "ko": "여자가 두 번째 대사에서 베이 브리지의 교통량이 걱정된다며, 차량들로 혼잡한 게 일상적이라서 거기에 갈 때는 항상 최소 한 시간은 더 잡아야 한다(I'm concerned about Bay Bridge traffic. It's routinely congested with vehicles. So you should always add at least an extra hour ~)고 덧붙이고 있으므로 정답은 (C)이다. Paraphrasing: 대화의 congested with vehicles → 정답의 Traffic"}, {"n": 37, "q": "What does the man say he will check?", "opts": ["Some webcams", "A list of ingredients", "An address", "Some maps"], "ans": 0, "ko": "남자가 마지막 대사에서 교통 웹캠들도 확인해 보겠다(I'll also check traffic Webcams ~)고 했으므로 정답은 (A)이다."}], "script": [{"sp": "W", "en": "Chen, I hope all is going well on your first day. I saw you have some scheduled seafood deliveries across the bay in the Morgan District. Why haven't you left yet?", "ko": "첸, 근무 첫날인데 모든 일이 순조롭게 진행되고 있기를 바랍니다. 만 건너편의 모건 지역에 해산물 배송 업무가 예정되어 있는 걸 봤어요. 왜 아직 출발하지 않았나요?"}, {"sp": "M", "en": "I wasn't going to head over to that particular area for another hour. Do the restaurants in the Morgan District want their deliveries earlier than scheduled?", "ko": "한 시간 더 있다가 그 지역으로 갈 생각이었어요. 모건 지역에 있는 레스토랑들이 예정보다 빨리 배송받길 원하나요?"}, {"sp": "W", "en": "No, but I'm concerned about Bay Bridge traffic. It's routinely congested with vehicles. So you should always add at least an extra hour to your trip out there.", "ko": "아니요, 하지만 베이 브리지의 교통량이 걱정됩니다. 차량들로 혼잡한 게 일상적이거든요. 그래서 거기에 갈 때는 항상 최소 한 시간은 더 잡아야 해요."}, {"sp": "M", "en": "Thanks for the tip. I'll also check traffic Webcams on the highway agency's Web site.", "ko": "팁 감사합니다. 고속도로 관리국의 웹사이트에서 교통 웹캠들도 확인해 볼게요."}]}, {"start": 38, "part": 3, "intro": "", "graphic": false, "speakers": "M-Au / W-Br", "audio": "Test_04-38-40.mp3", "qs": [{"n": 38, "q": "According to the man, what does Pelicon produce?", "opts": ["Household cleaners", "Cosmetics", "Industrial textiles", "Pharmaceuticals"], "ans": 1, "ko": "남자가 첫 대사에서 지역 화장품 생산업체인 펠리컨(Pelicon, a local producer of beauty products)이라고 했으므로 정답은 (B)이다. Paraphrasing: 대화의 beauty products → 정답의 Cosmetics"}, {"n": 39, "q": "What does the woman say she is concerned about?", "opts": ["Hiring skilled workers", "Securing a bank loan", "Finding transportation", "Making enough product"], "ans": 3, "ko": "여자가 첫 대사에서 다른 고객의 수요를 충족할 수 있을 만큼 라놀린을 충분히 생산하지 못할까 봐 걱정(I'm worried that we don't produce enough lanolin to meet the demand of another client)이라고 했으므로 정답은 (D)이다. Paraphrasing: 대화의 produce enough lanolin → 정답의 Making enough product"}, {"n": 40, "q": "Why does the man recommend reading an e-mail?", "opts": ["To consider a business proposal", "To prepare for a client meeting", "To view some construction plans", "To learn the details of a complaint"], "ans": 0, "ko": "남자가 두 번째 대사에서 현재 업체와의 계약이 거의 만료되었고, 갱신될 거라는 보장도 없다(our contract ~ has almost expired—there's no guarantee it will be renewed)며, 펠리컨의 제안서를 읽어는 봐야 한다(I think you should at least read Pelicon's proposal)고 했다. 이는 현재 사업이 어떻게 될지 모르니 펠리컨의 사업 제안을 고려해 보라는 것이므로 (A)가 정답이다."}], "script": [{"sp": "M", "en": "This morning I got an e-mail from Pelicon, a local producer of beauty products. They're interested in purchasing lanolin from us to use in their new line of all-natural makeup.", "ko": "오늘 아침에 지역 화장품 생산업체인 펠리컨으로부터 이메일을 하나 받았어요. 새로운 천연 화장품 라인에 사용할 라놀린을 구매하는 데 관심이 있네요."}, {"sp": "W", "en": "I'm not sure about that. We're a fairly small farm, and we already sell lanolin to another local business. I'm worried that we don't produce enough lanolin to meet the demand of another client. I don't want to expand and take on more wool production.", "ko": "잘 모르겠네요. 우리는 꽤 작은 농장이고, 이미 라놀린을 다른 지역 업체에 판매하고 있잖아요. 다른 고객의 수요를 충족할 수 있을 만큼 라놀린을 충분히 생산하지 못할까 봐 걱정입니다. 확장해서 더 많은 양모 생산을 맡고 싶지 않아요."}, {"sp": "M", "en": "But our contract with the business we currently supply lanolin to has almost expired—there's no guarantee it will be renewed. I think you should at least read Pelicon's proposal.", "ko": "하지만 현재 라놀린을 공급하는 업체와의 계약이 거의 만료되었고, 갱신될 거라는 보장도 없어요. 최소한 펠리컨의 제안서를 읽어는 봐야 한다고 생각합니다."}, {"sp": "W", "en": "Sure. Can you forward me the e-mail?", "ko": "좋아요. 제게 그 이메일을 전달해 주시겠어요?"}]}, {"start": 41, "part": 3, "intro": "", "graphic": false, "speakers": "M-Cn / W-Am", "audio": "Test_04-41-43.mp3", "qs": [{"n": 41, "q": "What will the woman do next month?", "opts": ["Reorganize a department", "Attend a conference", "Relocate to an overseas office", "Take a vacation"], "ans": 2, "ko": "남자가 첫 대사에서 여자가 뉴질랜드 지사에서 해외 근무를 하게 된다고 들었다(I heard you're going to be working for our company overseas, in the New Zealand office)고 했으므로 정답은 (C)이다. Paraphrasing: 대화의 working for our company overseas, in the New Zealand office → 정답의 Relocate to an overseas office"}, {"n": 42, "q": "What does the man want the woman to do?", "opts": ["Help with some contracts", "Prepare a project timeline", "Update some software", "Call a sales representative"], "ans": 0, "ko": "남자가 두 번째 대사에서 여자에게 계약을 갱신할 때가 되어서, 떠나기 전에 그 건의 처리를 요청하고 싶었다(It's time to renew the contracts, and I wanted to ask you to take care of that before you left)고 했으므로 정답은 (A)이다."}, {"n": 43, "q": "What does the woman ask the man for?", "opts": ["Some employee names", "Some credit card information", "A file password", "A telephone number"], "ans": 2, "ko": "여자가 마지막 대사에서 파일들을 언급하며, 이용하려면 비밀번호만 있으면 될 것(~ I'll just need the password to access them)이라고 했으므로 정답은 (C)이다."}], "script": [{"sp": "M", "en": "Nisreen? This is Lewis. I heard you're going to be working for our company overseas, in the New Zealand office. What a great opportunity!", "ko": "니즈린? 루이스입니다. 뉴질랜드 지사에서 해외 근무를 하게 된다고 들었어요. 정말 좋은 기회입니다!"}, {"sp": "W", "en": "Yes, thank you. I start next month, and I'm really excited.", "ko": "네, 감사합니다. 다음 달에 시작하는데, 정말 기대됩니다."}, {"sp": "M", "en": "I'm calling to touch base with you about some of our vendor contracts. It's time to renew the contracts, and I wanted to ask you to take care of that before you left.", "ko": "판매업체 계약과 관련해 몇 가지 협의하기 위해 전화했어요. 계약을 갱신할 때가 되어서, 떠나시기 전에 그 건의 처리를 요청하고 싶었어요."}, {"sp": "W", "en": "No problem. I know where those files are located on our shared computer drive. I'll just need the password to access them.", "ko": "문제없습니다. 우리 공용 컴퓨터 드라이브에서 그 파일들이 어디에 있는지 알아요. 이용하려면 비밀번호만 있으면 될 거예요."}]}, {"start": 44, "part": 3, "intro": "", "graphic": false, "speakers": "W-Br / M-Cn", "audio": "Test_04-44-46.mp3", "qs": [{"n": 44, "q": "Why is the woman calling?", "opts": ["To negotiate a payment", "To reschedule an appearance", "To book a venue", "To ask about security"], "ans": 1, "ko": "여자가 첫 대사에서 자신이 지오바니 마리노의 대리인이라며, 〈선데이 모닝 쇼〉 출연 일정을 재조정하기 위해 전화했다(This is Giovanni Marino's agent. I'm calling to reschedule his planned appearance on the Sunday Morning Show)고 했으므로 정답은 (B)이다."}, {"n": 45, "q": "Who most likely is Giovanni Marino?", "opts": ["An actor", "A politician", "A writer", "A photographer"], "ans": 0, "ko": "남자가 첫 대사에서 지오바니 마리노의 신작 영화(his new movie)를 언급했고, 여자도 그가 출연 중인 영화(the movie he's acting in)라고 했으므로 정답은 (A)이다."}, {"n": 46, "q": "What will the man send in an e-mail?", "opts": ["A revised contract", "A reimbursement form", "An invitation to a video conference", "Directions to a location"], "ans": 0, "ko": "남자가 마지막 대사에서 새로운 날짜로 계약서를 업데이트해서 이메일로 보낼 것(I'll update the contract with the new date and e-mail it to you)이라고 했으므로 정답은 (A)이다. Paraphrasing: 대화의 update the contract with the new date → 정답의 A revised contract"}], "script": [{"sp": "W", "en": "Hi. This is Giovanni Marino's agent. I'm calling to reschedule his planned appearance on the Sunday Morning Show.", "ko": "안녕하세요. 지오바니 마리노의 대리인입니다. 계획되어 있는 〈선데이 모닝 쇼〉 출연 일정을 재조정하기 위해 전화했습니다."}, {"sp": "M", "en": "Right. We have him booked to appear on the show in July to promote his new movie.", "ko": "맞아요. 신작 영화를 홍보하실 수 있게 7월에 프로그램 출연을 예약해 드렸습니다."}, {"sp": "W", "en": "Unfortunately, the movie he's acting in is behind schedule, and he'll now be on location through the end of August.", "ko": "안타깝게도, 출연 중인 영화의 촬영이 예정보다 늦어져, 이제는 8월 말까지 현지 촬영이 진행될 예정이에요."}, {"sp": "M", "en": "Hmm, I see. Let me look at our guest calendar. I have a slot I'm looking to fill on September fourteenth—would that work?", "ko": "흠, 알겠습니다. 저희 초대 손님 일정표를 확인해 보겠습니다. 9월 14일에 채우려고 하는 자리가 하나 있는데, 그 날짜 괜찮을까요?"}, {"sp": "W", "en": "Yes, that would be great, thanks.", "ko": "네, 그럼 아주 좋겠네요. 감사합니다."}, {"sp": "M", "en": "All right. I'll update the contract with the new date and e-mail it to you.", "ko": "좋습니다. 새로운 날짜로 계약서를 업데이트해서 이메일로 보내 드리겠습니다."}]}, {"start": 47, "part": 3, "intro": "", "graphic": false, "speakers": "M-Cn / W-Br / M-Au (3인 대화)", "audio": "Test_04-47-49.mp3", "qs": [{"n": 47, "q": "What are the speakers discussing?", "opts": ["A conference schedule", "A company policy", "A catering menu", "A supply order"], "ans": 1, "ko": "여자가 첫 대사에서 원격 근무자들을 대상으로 하는 새로운 회사 정책에 대한 생각을 이야기하고 있다(We're talking about our thoughts on the new company policy for remote workers)고 했으므로 정답은 (B)이다."}, {"n": 48, "q": "What do the men want to do?", "opts": ["Rent a car", "Go to a restaurant", "Speak with a manager", "Change some flight reservations"], "ans": 2, "ko": "남자1이 좋은 지적이라며 다같이 이사님께 가서 함께 이 문제를 논의해 보자(Let's all go to the director to discuss this with her)고 했고, 남자2도 사무실에 계신 것 같으니 지금이 좋은 때(I believe she's in her office, so now's a good time)라고 했으므로 정답은 (C)이다."}, {"n": 49, "q": "What does the woman say she needs to do now?", "opts": ["Work on a report", "Meet with a client", "Print some materials", "Check her e-mails"], "ans": 0, "ko": "여자는 지금 무엇을 해야 한다고 말하는가? 세부 사항 관련 – 여자가 지금 해야 할 일. 여자가 마지막 대사에서 정오까지 마무리해야 하는 보고서가 있다(I have a report to finalize by noon)고 했으므로 정답은 (A)이다."}], "script": [{"sp": "M", "en": "Hello, Usha. Hi, Pablo.", "ko": "안녕하세요, 우샤. 안녕하세요, 파블로."}, {"sp": "W", "en": "Hey, Konstantin. We're talking about our thoughts on the new company policy for remote workers. On the days I have to come into the office, I always worry about finding an appropriate workstation.", "ko": "안녕하세요, 콘스탄틴. 저희는 원격 근무자들을 대상으로 하는 새로운 회사 정책에 대한 생각을 이야기하고 있어요. 회사에 출근해야 하는 날에는, 항상 적당한 업무 자리를 찾는 게 걱정이에요."}, {"sp": "M", "en": "Yeah, I don't like the unpredictability either. Why can't we just sign up for our workstation sometime in advance? What do you think about it?", "ko": "네, 저도 예측 불가능성이 마음에 들지 않아요. 왜 저희가 미리 저희 업무 자리를 신청할 수 없는 건가요? 이 부분에 대해 어떻게 생각하세요?"}, {"sp": "M", "en": "These are good points. Let's all go to the director to discuss this with her.", "ko": "좋은 지적입니다. 다같이 이사님께 가서 함께 이 문제를 논의해 봅시다."}, {"sp": "M", "en": "I believe she's in her office, so now's a good time.", "ko": "사무실에 계신 것 같으니, 지금이 좋은 때입니다."}, {"sp": "W", "en": "Oh, I can't go now. I have a report to finalize by noon.", "ko": "아, 저는 지금 갈 수 없어요. 정오까지 마무리해야 하는 보고서가 있어요."}]}, {"start": 50, "part": 3, "intro": "", "graphic": false, "speakers": "W-Br / M-Cn", "audio": "Test_04-50-52.mp3", "qs": [{"n": 50, "q": "Who most likely is the woman?", "opts": ["A journalist", "A librarian", "A musician", "A software developer"], "ans": 1, "ko": "여자는 누구인 것 같은가? 전체 내용 관련 – 여자의 직업. 여자가 첫 대사에서 남자에게 새 도서관 카드(Here's your new library card)를 건네며, 도서관에서 빌릴 수 있는 자료들에 대해 설명하고 있으므로 정답은 (B)이다."}, {"n": 51, "q": "What does the woman recommend that the man do?", "opts": ["Consult a manual", "Sign up for a class", "Listen to some music", "Use a particular mobile app"], "ans": 3, "ko": "여자는 남자에게 무엇을 하도록 권하는가? 세부 사항 관련 – 여자가 권하는 것. 여자가 두 번째 대사에서 클라우드-캐멀 애플리케이션을 다운로드해서 카드에 있는 정보를 이용해 계정을 설정하기만 하면 된다(We offer the Cloud-Camel application. All you have to do is download the app ~)고 설명하고 있으므로 정답은 (D)이다."}, {"n": 52, "q": "What does the man say happens each month?", "opts": ["He publishes a blog post.", "He meets with a social group.", "He travels for work.", "He volunteers for a community event."], "ans": 2, "ko": "남자는 매달 무슨 일이 있다고 말하는가? 세부 사항 관련 – 남자가 매달 있다고 말하는 일. 남자가 마지막 대사에서 매달 출장을 떠난다(I go on a business trip every month ~)고 했으므로 정답은 (C)이다."}], "script": [{"sp": "W", "en": "OK, Mr. Jebreen. Here's your new library card. Remember that you can borrow books, CDs, and DVDs from our collection with it.", "ko": "자, 제브린 씨. 여기 새 도서관 카드입니다. 이 카드로 저희 소장 자료 중 도서와 CD, DVD를 빌리실 수 있다는 점을 기억해 주세요."}, {"sp": "M", "en": "Thank you. I read somewhere that people can also borrow digital items.", "ko": "감사합니다. 어디선가 디지털 자료도 빌릴 수 있다고 읽었어요."}, {"sp": "W", "en": "Yes! We offer the Cloud-Camel application. All you have to do is download the app and use the information on your card to set up an account.", "ko": "네! 클라우드-캐멀 애플리케이션을 제공합니다. 이 앱을 다운로드해서 갖고 계신 카드에 있는 정보를 이용해 계정을 설정하기만 하면 됩니다."}, {"sp": "M", "en": "That's great. I go on a business trip every month, so having easy access to online content will be convenient.", "ko": "아주 좋네요. 저는 매달 출장을 떠나기 때문에, 온라인 콘텐츠를 쉽게 이용할 수 있다면 편리할 거예요."}]}, {"start": 53, "part": 3, "intro": "", "graphic": false, "speakers": "W-Am / M-Cn", "audio": "Test_04-53-55.mp3", "qs": [{"n": 53, "q": "What does the woman want the man to look at?", "opts": ["A marketing plan", "A conference calendar", "Schedule changes", "Survey results"], "ans": 3, "ko": "여자는 남자가 무엇을 보기를 원하는가? 세부 내용 관련 – 여자가 남자에게 보라고 하는 것. 여자가 첫 대사에서 남자에게 사내 설문 조사 데이터를 검토했는지 물으며, 꼭 검토해야 한다(Have you reviewed the data from the workplace survey? You really should)고 했으므로 정답은 (D)이다."}, {"n": 54, "q": "What does the man imply when he says, \"the company's certainly had other priorities\"?", "opts": ["His workload has decreased.", "He is not responsible for some results.", "Some criticism is accurate.", "Some decisions led to a successful outcome."], "ans": 2, "ko": "남자가 \"회사에 분명 다른 우선 순위들이 있었죠\"라고 말할 때 무엇을 암시하는가? 화자의 의도 파악 – 회사에 다른 우선 순위들이 있었다는 말의 의도. 여자가 첫 대사에서 거의 40퍼센트는 개인의 기여를 인정받지 못하고 있다고 느낀다(But almost 40 percent feel like their individual contributions aren't being recognized)고 말하자, 남자가 인용문을 언급하고 있다. 이는 40퍼센트의 직원들이 갖고 있는 부정적인 의견에 대해 공감한다는 뜻을 나타내는 것이므로 정답은 (C)이다."}, {"n": 55, "q": "What has the woman suggested in the past?", "opts": ["Rewarding staff performance", "Extending business hours", "Encouraging professional development", "Organizing team-building events"], "ans": 0, "ko": "여자는 과거에 무엇을 제안한 적이 있는가? 세부 사항 관련 – 여자가 과거에 제안한 것. 여자가 마지막 대사에서 매 분기마다 뛰어난 성과에 대해 상을 수여해야 한다고 여러 번 제안했다(I've suggested many times that they give out awards every quarter for exceptional performance)고 했으므로 정답은 (A)이다."}], "script": [{"sp": "W", "en": "Have you reviewed the data from the workplace survey? You really should. It looks like most staff feel positive about the direction that the company is going in. But almost 40 percent feel like their individual contributions aren't being recognized.", "ko": "사내 설문 조사 데이터를 검토하셨나요? 꼭 검토해야 해요. 대부분의 직원들이 회사가 나아가고 있는 방향에 대해 긍정적으로 생각하는 것 같아요. 하지만 거의 40퍼센트는 개인의 기여를 인정받지 못하고 있다고 느끼고 있어요."}, {"sp": "M", "en": "Well, the company's certainly had other priorities. I wonder how the management team's going to respond.", "ko": "음, 회사에 분명 다른 우선 순위들이 있었죠. 경영진이 어떻게 반응할지 궁금하네요."}, {"sp": "W", "en": "I've suggested many times that they give out awards every quarter for exceptional performance. Maybe now they'll finally start doing it.", "ko": "제가 매 분기마다 뛰어난 성과에 대해 상을 수여해야 한다고 여러 번 제안했어요. 이제야 드디어 그걸 시작할지도 모르겠네요."}]}, {"start": 56, "part": 3, "intro": "", "graphic": false, "speakers": "W-Am / M-Au / W-Br", "audio": "Test_04-56-58.mp3", "qs": [{"n": 56, "q": "What type of business do the women own?", "opts": ["A hair salon", "A recording studio", "A clothing company", "A fitness center"], "ans": 2, "ko": "여자들은 어떤 종류의 업체를 소유하고 있는가? 세부 사항 관련 – 여자들이 소유한 업체. 첫 번째 여자가 첫 대사에서 최근에 의류 회사를 시작했다(~ my colleague and I recently started a clothing company ~)고 했으므로 정답은 (C)이다."}, {"n": 57, "q": "What does the man say regarding television?", "opts": ["It is an industry he once worked in.", "It reaches more people than magazines.", "It needs more programs about sports.", "It is not the only advertising platform available."], "ans": 3, "ko": "남자는 텔레비전과 관련해 무슨 말을 하는가? 세부 사항 관련 – 남자가 텔레비전과 관련해 하는 말. 남자가 첫 대사에서 텔레비전이 광고 분야의 전부는 아니다(~ television is definitely not the entire advertising landscape)라고 했으므로 정답은 (D)이다."}, {"n": 58, "q": "According to the man, why would Saskia Hoffman be a good choice?", "opts": ["She recently won an award.", "She lives nearby.", "She charges affordable rates.", "She is well known in her field."], "ans": 3, "ko": "남자에 따르면, 사스키아 호프먼이 왜 좋은 선택이 될 것인가? 세부 사항 관련 – 사스키아 호프먼이 좋은 선택인 이유. 남자가 마지막 대사에서 많은 사람들이 그녀의 온라인 운동 루틴을 활용하고 있고, 시청자들은 그녀가 추천하고 착용하는 것에 관심을 기울일 것(~ lots of people use her online exercise routines. Her viewers will pay attention to what she recommends and wears)이라고 했다. 이는 호프먼이 많은 사람들에게 영향을 미치고 있다는 뜻으로, 자신의 분야에서 잘 알려져 있음을 나타내는 말이므로 정답은 (D)이다."}], "script": [{"sp": "W", "en": "Hi, Ajiola. As I mentioned on the phone, my colleague and I recently started a clothing company and are hoping your branding firm can help us promote our line of athletic apparel. You think we should focus on advertising on social media, right?", "ko": "안녕하세요, 아지올라. 전화상으로 말씀드렸듯이, 제 동료와 제가 최근에 의류 회사를 시작해서, 귀하의 브랜딩 회사에서 저희 운동복 라인을 홍보하는 데 도움을 줄 수 있기를 바랍니다. 저희가 소셜 미디어 광고에 초점을 맞춰야 한다고 생각하시는 거죠, 그렇죠?"}, {"sp": "M", "en": "Right. Contrary to popular belief, television is definitely not the entire advertising landscape. Advertising on the Internet is also a great way for a company to increase its visibility.", "ko": "그렇습니다. 일반적인 생각과 달리, 텔레비전이 광고 분야의 전부는 아닙니다. 인터넷 광고 또한 회사의 인지도를 높일 수 있는 훌륭한 방법입니다."}, {"sp": "W", "en": "I heard you recommended working with an online influencer.", "ko": "온라인 인플루언서와 협업하는 것을 추천한다고 들었어요."}, {"sp": "M", "en": "Yes—Saskia Hoffman. Saskia's very knowledgeable about exercise, and lots of people use her online exercise routines. Her viewers will pay attention to what she recommends and wears.", "ko": "네, 사스키아 호프먼이요. 사스키아는 운동에 대해 아는 것이 많고, 많은 사람들이 그녀의 온라인 운동 루틴을 활용하고 있어요. 시청자들은 그녀가 추천하고 착용하는 것에 관심을 기울일 것입니다."}]}, {"start": 59, "part": 3, "intro": "", "graphic": false, "speakers": "W-Br / M-Au", "audio": "Test_04-59-61.mp3", "qs": [{"n": 59, "q": "What does the speakers' company manufacture?", "opts": ["Art supplies", "Puzzles", "Shipping materials", "Power tools"], "ans": 1, "ko": "화자들의 회사는 무엇을 제조하는가? 전체 내용 관련 – 화자들의 회사가 제조하는 것. 여자가 첫 대사에서 백화점 체인에서 받은 주문(~ the order we got from the department store chain)을 언급하며, 조각 퍼즐 5,000개를 주문한 곳(~ the one that placed an order for 5,000 jigsaw puzzles)이라고 했으므로 정답은 (B)이다."}, {"n": 60, "q": "What does the woman imply when she says, \"A week is not a long time\"?", "opts": ["Some prices will likely increase.", "Some temporary employees have been hired.", "A colleague's work is excellent.", "An order may not be filled."], "ans": 3, "ko": "여자가 \"일주일은 긴 시간이 아닙니다\"라고 말할 때 무엇을 의미하는가? 화자의 의도 파악 – 일주일은 긴 시간이 아니라는 말의 의도. 남자가 첫 대사에서 주문한 업체가 연휴 전에 재고를 갖출 수 있도록 일주일 후에 주문한 것을 받기를 원한다(They want the order in a week so they can stock them before the holiday)고 말하자, 여자가 인용문을 언급하고 있다. 이는 일주일이 긴 시간이 아니기 때문에 주문을 이행하지 못할 수도 있다고 말하는 것이므로 정답은 (D)이다."}, {"n": 61, "q": "What will the woman do next?", "opts": ["Review a contract", "Print out an invoice", "Share some illustrations", "Confirm a client meeting"], "ans": 2, "ko": "여자는 다음에 무엇을 할 것인가? 세부 사항 관련 – 여자가 다음에 할 일. 남자가 두 번째 대사에서 삽화가들이 새 퍼즐용 삽화를 보냈는지(~ our illustrators sent some new puzzle illustrations, right?) 묻자, 여자가 그 스케치를 갖고 있다며 보여 주겠다(I've got the sketches right here. Let me show you)고 했으므로 정답은 (C)이다."}], "script": [{"sp": "W", "en": "Hi, Shinji. I wanted to ask you about the order we got from the department store chain. You know, the one that placed an order for 5,000 jigsaw puzzles?", "ko": "안녕하세요, 신지. 우리가 백화점 체인에서 받은 주문에 대해 물어보고 싶었어요. 그러니까, 조각 퍼즐 5,000개를 주문한 곳 있잖아요?"}, {"sp": "M", "en": "Yes. They want the order in a week so they can stock them before the holiday.", "ko": "네. 그곳에서 연휴 전에 재고를 갖출 수 있도록 일주일 후에 주문한 것을 받기를 원해요."}, {"sp": "W", "en": "A week is not a long time.", "ko": "일주일은 긴 시간이 아닙니다."}, {"sp": "M", "en": "We've had short timelines before. Anyway, our illustrators sent some new puzzle illustrations, right? I heard they're making a special edition.", "ko": "전에도 일정이 짧았던 적이 있었어요. 그건 그렇고, 우리 삽화가들이 새 퍼즐용 삽화를 보냈죠, 그렇죠? 특별판을 만들고 있다고 들었어요."}, {"sp": "W", "en": "Yes, and I'm so excited! I've got the sketches right here. Let me show you.", "ko": "네, 너무 기대돼요! 바로 여기 그 스케치가 있어요. 제가 보여 드릴게요."}]}, {"start": 62, "part": 3, "intro": "", "graphic": true, "speakers": "M-Au / W-Am", "audio": "Test_04-62-64.mp3", "qs": [{"n": 62, "q": "Where does the man most likely work?", "opts": ["At an airport", "At a bank", "At a real estate agency", "At a department store"], "ans": 1, "ko": "남자는 어디에서 일하는 것 같은가? 전체 내용 관련 – 남자의 근무 장소. 남자가 첫 대사에서 여자가 사업자용 계좌 명세서에 표시되어 있는 청구 금액에 대해 우려하는 것으로 안다(I understand you're concerned about a charge that appears on the statement for your business account)고 했고, 관련 질문에 응답하고 있으므로 정답은 (B)이다."}, {"n": 63, "q": "Look at the graphic. Which amount does the woman ask about?", "opts": ["$203.00", "$350.00", "$75.50", "$83.15"], "ans": 0, "ko": "시각 정보에 의하면, 여자는 어느 금액에 대해 묻는가? 시각 정보 연계 – 여자가 묻는 금액. 여자가 첫 대사에서 5월 3일 청구 금액에 대해 질문이 있다(I have a question about the charge on May 3)고 했고, 청구 내역서에서 5월 3일 총액은 203.00달러이므로 정답은 (A)이다."}, {"n": 64, "q": "What does the man give the woman?", "opts": ["An updated statement", "A list of fees", "A discount card", "A brochure"], "ans": 1, "ko": "남자는 여자에게 무엇을 주는가? 세부 사항 관련 – 남자가 여자에게 주는 것. 여자가 두 번째 대사에서 해외 거래에 대한 모든 은행 수수료 목록을 제공해 줄 것(Can you provide me with a list of all the bank fees for transactions made abroad?)을 요청했고, 남자가 알겠다(Yes, of course)고 했으므로 정답은 (B)이다."}], "script": [{"sp": "M", "en": "Hi, Ms. Rossi. I understand you're concerned about a charge that appears on the statement for your business account.", "ko": "안녕하세요, 로시 씨. 사업자용 계좌 명세서에 표시되어 있는 청구 금액에 대해 우려하시는 것으로 알고 있습니다."}, {"sp": "W", "en": "Yes, I have a question about the charge on May 3. I don't remember purchasing anything for that amount.", "ko": "네, 5월 3일 청구 금액에 대해 질문이 있습니다. 해당 금액으로 아무것도 구매한 기억이 없습니다."}, {"sp": "M", "en": "Let me review your statement now. Hmm. It looks like that purchase was made abroad. So an international transaction fee was added to the purchase amount.", "ko": "지금 그 내역서를 살펴보겠습니다. 흠. 그 구매가 해외에서 이뤄진 것으로 보입니다. 그래서 해외 거래 수수료가 그 구매 금액에 추가되었습니다."}, {"sp": "W", "en": "Oh, yes—I was out of the country at that time. Thanks for clarifying. Can you provide me with a list of all the bank fees for transactions made abroad?", "ko": "아, 네. 제가 그때 해외에 있었습니다. 명확히 해 주셔서 감사합니다. 해외 거래에 대한 모든 은행 수수료 목록을 제공해 주실 수 있나요?"}, {"sp": "M", "en": "Yes, of course. Here's a document that lists all the information.", "ko": "네, 물론입니다. 여기 모든 정보가 나열된 문서입니다."}], "gimg": "ets_t4_g62.jpg"}, {"start": 65, "part": 3, "intro": "", "graphic": true, "speakers": "M-Cn / W-Am", "audio": "Test_04-65-67.mp3", "qs": [{"n": 65, "q": "What does the man thank the woman for doing?", "opts": ["Printing programs", "Setting up lighting", "Reserving a venue", "Paying a performer"], "ans": 2, "ko": "남자는 여자가 무엇을 한 것에 대해 고마워하는가? 전체 내용 관련 – 남자가 고마워하는 것. 여자가 첫 대사에서 대강당을 예약했다(I booked their main auditorium for that day)고 말하자, 남자가 그렇게 해 주어 고맙다(Thanks for doing that)고 했으므로 정답은 (C)이다."}, {"n": 66, "q": "What does the man say he is worried about?", "opts": ["Reviews from critics", "Ticket sales", "A performance schedule", "The cost of merchandise"], "ans": 1, "ko": "남자는 무엇에 대해 걱정된다고 말하는가?"}, {"n": 67, "q": "Look at the graphic. Where will a table be set up?", "opts": ["At location 1", "At location 2", "At location 3", "At location 4"], "ans": 3, "ko": "남자가 마지막 대사에서 카페 옆에 설치하자(Let's set it up next to the café)고 했고, 안내도에서 카페 옆은 4번이므로 정답은 (D)이다."}], "script": [{"sp": "M", "en": "Magali, were you able to reserve the performing arts center for the piano concert?", "ko": "마갈리, 피아노 콘서트를 위해 공연 예술 센터를 예약하실 수 있었나요?"}, {"sp": "W", "en": "Yes. I booked their main auditorium for that day. They're sending me the contract.", "ko": "네. 그날 대강당을 예약했어요. 제게 계약서를 보내 줄 거예요."}, {"sp": "M", "en": "Thanks for doing that.", "ko": "그렇게 해 주셔서 감사합니다."}, {"sp": "W", "en": "No problem. Hopefully, it'll be as successful as last year.", "ko": "별말씀을요. 작년처럼 성공적인 행사가 되길 바랍니다."}, {"sp": "M", "en": "We sold 2,000 tickets last year, but we had three celebrity performers. I'm worried we won't sell as many tickets this year.", "ko": "작년에는 티켓을 2,000장 판매했는데, 유명 연주자가 세 명 있었잖아요. 올해는 티켓을 그만큼 많이 판매하지 못할까 봐 걱정이에요."}, {"sp": "W", "en": "Well, Xinyu Gu is a very popular pianist. And she's staying after the concert to sign autographs. Which reminds me, where should we set up the table for that?", "ko": "음, 신유 구는 매우 유명한 피아니스트입니다. 그리고 공연이 끝난 후에 남아서 사인을 해 줄 거예요. 그러고 보니 그것을 위한 테이블을 어디에 설치해야 할까요?"}, {"sp": "M", "en": "Good question. Hmm. The café should be closed by then. Let's set it up next to the café.", "ko": "좋은 질문입니다. 흠. 카페가 그때쯤 문을 닫을 거예요. 카페 옆에 설치합시다."}], "gimg": "ets_t4_g65.jpg"}, {"start": 68, "part": 3, "intro": "", "graphic": true, "speakers": "M-Au / W-Br", "audio": "Test_04-68-70.mp3", "qs": [{"n": 68, "q": "Why is the woman at the garden center?", "opts": ["To enroll in a course", "To join a gardening club", "To buy some supplies", "To return a purchase"], "ans": 2, "ko": "여자가 첫 대사에서 장미 덤불을 기르기 시작했는데, 추천 제품이 있는지(I've started growing rose bushes, ~ Are there any products you can recommend?) 묻고 있으므로 정답은 (C)이다."}, {"n": 69, "q": "Look at the graphic. Which month's post will the woman most likely read?", "opts": ["May's post", "June's post", "July's post", "August's post"], "ans": 0, "ko": "남자가 세 번째 대사에서 장미 재배에 관한 최신 글이 있다(~ there's a recent one about growing roses)고 하자, 여자가 확인해 보겠다(I'll check it out)고 했고, 블로그 게시글 목록에서 5월(May) 게시글이 장미 재배(Growing roses)에 관한 것임을 알 수 있으므로 정답은 (A)이다."}, {"n": 70, "q": "What kind of products will the man show to the woman?", "opts": ["Indoor plants", "Plant fertilizers", "Gardening tools", "Irrigation systems"], "ans": 1, "ko": "남자가 마지막 대사에서 비료를 보여 주겠다(~ let me show you our fertilizers)고 했으므로 정답은 (B)이다."}], "script": [{"sp": "M", "en": "Welcome to the garden center. Can I help you?", "ko": "원예 용품점에 오신 것을 환영합니다. 무엇을 도와드릴까요?"}, {"sp": "W", "en": "Hi. I've started growing rose bushes, and I've heard they require special care. Are there any products you can recommend?", "ko": "안녕하세요. 장미 덤불을 기르기 시작했는데, 특별 관리가 필요하다고 들었어요. 추천해 주실 제품이 있나요?"}, {"sp": "M", "en": "Yes! But first, I'd like to show you a great resource on our Web site. Have you seen our blog?", "ko": "네! 하지만 우선, 저희 웹사이트에 있는 아주 좋은 자료를 보여 드리고 싶습니다. 저희 블로그를 보신 적 있으세요?"}, {"sp": "W", "en": "No, I haven't.", "ko": "아니요, 없어요."}, {"sp": "M", "en": "We have monthly posts on many gardening topics, and there's a recent one about growing roses.", "ko": "다양한 원예 주제에 관해서 매달 게시글을 올리는데, 장미 재배에 관한 최신 글이 있어요."}, {"sp": "W", "en": "I'll check it out! Thanks so much.", "ko": "확인해 볼게요! 정말 감사합니다."}, {"sp": "M", "en": "You're welcome. Now—let me show you our fertilizers. They're in aisle six.", "ko": "별말씀을요. 이제 저희 비료들을 보여 드리겠습니다. 6번 통로에 있어요."}], "gimg": "ets_t4_g68.jpg"}, {"start": 71, "part": 4, "intro": "", "graphic": false, "speakers": "W-Br", "audio": "Test_04-71-73.mp3", "qs": [{"n": 71, "q": "What field does the speaker most likely work in?", "opts": ["Finance", "Transportation", "Construction", "Robotics"], "ans": 1, "ko": "화자가 초반부에 카셀라 교통 고객에게 알린다며, 적색 및 황색 노선의 유지 관리 작업이 다음 주에 시작될 것(Attention, Casella Transit customers. Maintenance work on the red and yellow lines will begin next week)이라고 했으므로 정답은 (B)이다."}, {"n": 72, "q": "What does the speaker say the listeners can receive notifications about?", "opts": ["Route changes", "Mobile app updates", "New products", "Schedule delays"], "ans": 3, "ko": "화자가 중반부에 열차가 영향을 받는 경우에 지연과 관련된 알림을 받을 수 있다(You can receive notifications regarding delays if your train is impacted)고 했으므로 정답은 (D)이다."}, {"n": 73, "q": "According to the speaker, how can the listeners reduce a cost?", "opts": ["By purchasing a digital ticket", "By reserving multiple permits", "By traveling at less busy hours", "By joining a loyalty program"], "ans": 0, "ko": "화자가 후반부에 통근 교통비를 절약하고 싶은지 물으며, 모바일 앱을 통해 전자 승차권을 구입하라(Want to save on commuter rides? Purchase your e-ticket through the mobile app as well)고 했으므로 정답은 (A)이다."}], "script": [{"sp": "W", "en": "Attention, Casella Transit customers. Maintenance work on the red and yellow lines will begin next week. You can expect some disruptions to regular service, so please plan ahead. Use the latest version of our mobile phone application for real-time updates. You can receive notifications regarding delays if your train is impacted. Want to save on commuter rides? Purchase your e-ticket through the mobile app as well. Printing a ticket at a kiosk is now subject to additional fees.", "ko": "카셀라 교통 고객 여러분께 알립니다. 적색 및 황색 노선의 유지 관리 작업이 다음 주에 시작될 것입니다. 정규 서비스에 차질이 예상되오니, 미리 계획을 세우시기 바랍니다. 최신 버전의 저희 휴대폰 애플리케이션을 사용하여 실시간 업데이트를 확인하세요. 여러분의 열차가 영향을 받는 경우에 지연과 관련된 알림을 받을 수 있습니다. 통근 교통비를 절약하고 싶으신가요? 모바일 앱을 통해 전자 승차권을 구입하세요. 이제 단말기에서 승차권을 출력하면 추가 요금이 부과됩니다."}]}, {"start": 74, "part": 4, "intro": "", "graphic": false, "speakers": "W-Am", "audio": "Test_04-74-76.mp3", "qs": [{"n": 74, "q": "What is the purpose of the meeting?", "opts": ["To explain a restoration project", "To prepare for a public event", "To train some new tour guides", "To recruit some volunteers"], "ans": 0, "ko": "화자가 초반부에 원본 설계도를 발견했다며, 이 설계도를 바탕으로 정원을 복원할 것(So, we're going to restore the gardens based on those plans!)이라고 알리면서, 그와 관련해 이야기하고 있으므로 정답은 (A)이다."}, {"n": 75, "q": "According to the speaker, why will a task be challenging?", "opts": ["Funding has not been secured.", "Unfavorable weather is predicted.", "Some permits have been delayed.", "Some important information is missing."], "ans": 3, "ko": "화자가 중반부에 진짜 같이 재현하는 것은 쉬운 작업이 아니라며, 당시 어떤 종류의 식물이 재배되었는지 모른다(~ making an authentic re-creation won't be an easy task. We don't know what specific varieties of plants were grown back then)고 했으므로 정답은 (D)이다."}, {"n": 76, "q": "Who is Vivek Hazarika?", "opts": ["An architect", "A gardener", "A salesperson", "An archaeologist"], "ans": 1, "ko": "화자가 후반부에 비벡 하자리카가 많은 역사적 저택들의 부지를 관리해 온 정원사(As a gardener who has managed the grounds of many historic estates ~)라고 했으므로 정답은 (B)이다."}], "script": [{"sp": "W", "en": "Good morning, Glenman House Living Museum staff. Recently, researchers discovered the original plans for the house's gardens from the eighteenth century. So, we're going to restore the gardens based on those plans! Even though we have the original designs, making an authentic re-creation won't be an easy task. We don't know what specific varieties of plants were grown back then. That's why we're so lucky to have Vivek Hazarika consulting on this project. As a gardener who has managed the grounds of many historic estates, he has extensive expertise in what would have been planted at the time.", "ko": "안녕하세요, 글렌맨 하우스 리빙 박물관 직원 여러분. 최근에 연구원들이 18세기 이 저택 정원의 원본 설계도를 발견했습니다. 그래서 이 설계도를 바탕으로 정원을 복원할 것입니다! 우리가 원본 디자인을 갖고 있기는 하지만 진짜 같이 재현하는 것은 쉬운 작업이 아닙니다. 우리는 당시 어떤 종류의 식물이 재배되었는지 모릅니다. 그렇기 때문에 비벡 하자리카가 이 프로젝트를 컨설팅해 주는 것은 정말 행운입니다. 많은 역사적 저택들의 부지를 관리해 온 정원사로서, 당시 심었을 식물에 대한 폭넓은 전문 지식을 보유하고 있습니다."}]}, {"start": 77, "part": 4, "intro": "", "graphic": false, "speakers": "M-Cn", "audio": "Test_04-77-79.mp3", "qs": [{"n": 77, "q": "What is the purpose of the session?", "opts": ["To discuss customer feedback", "To explain an attendance policy", "To discourage mobile phone use", "To train new sales staff"], "ans": 3, "ko": "화자가 초반부에 오늘의 전화 영업 교육에 온 신입 영업 사원 여러분을 환영한다(Welcome, new sale representatives, to today's session on cold calling, ~)고 했으므로 정답은 (D)이다."}, {"n": 78, "q": "What will be on a list that the listeners will receive?", "opts": ["Potential clients to contact", "Employees who have exceeded sales goals", "Products offered by the company", "Departments within the company"], "ans": 0, "ko": "화자가 중반부에 청자들이 전화할 잠재 고객 명단을 받을 것(~ you'll each be given a list of prospective parties to call)이라고 했으므로 정답은 (A)이다."}, {"n": 79, "q": "What will the listeners do next?", "opts": ["Memorize prepared scripts", "Listen to recorded calls", "Take a brief survey", "Brainstorm conversational topics"], "ans": 1, "ko": "화자가 후반부에 이제 전화 영업 녹음을 들어보고 어떤 것이 효과적이고 어떤 것이 효과가 없는지 알아보겠다(Now we'll listen to some cold call recordings to learn what works and what doesn't)고 했으므로 정답은 (B)이다."}], "script": [{"sp": "M", "en": "Welcome, new sales representatives, to today's session on cold calling, a sales technique where we call potential clients who haven't heard of us yet. Toward the end of the session you'll each be given a list of prospective parties to call. Now, the people you're contacting are busy and may not be receptive. Your job's to persuade them that what you have to say is worth their while. Be friendly and avoid using scripts. Now we'll listen to some cold call recordings to learn what works and what doesn't.", "ko": "신입 영업 사원 여러분, 오늘의 전화 영업 교육에 오신 것을 환영합니다. 전화 영업은 아직 우리에 대해 들어보지 못한 잠재 고객들에게 전화를 거는 영업 기법입니다. 교육이 끝날 무렵에, 여러분은 각자 전화할 잠재 고객 명단을 받을 것입니다. 자, 여러분이 연락할 사람들이 바쁘고 수용적이지 않을 수도 있습니다. 여러분이 할 일은 여러분이 하는 말이 가치가 있다는 것을 설득하는 것입니다. 친절하게 대하고 원고를 이용하는 것을 피하세요. 이제 전화 영업 녹음을 들어보고 어떤 것이 효과적이고 어떤 것이 효과가 없는지 알아보겠습니다."}]}, {"start": 80, "part": 4, "intro": "", "graphic": false, "speakers": "M-Au", "audio": "Test_04-80-82.mp3", "qs": [{"n": 80, "q": "What does the speaker's company sell?", "opts": ["Sound systems", "Light fixtures", "Umbrellas", "Refrigerators"], "ans": 2, "ko": "화자가 초반부에 화자의 회사의 테라스용 파라솔을 이용하면서 겪은 문제들에 대해 직접 사과하고자 한다(I want to apologize personally for the problems your restaurant experienced using our patio umbrellas)고 했으므로 정답은 (C)이다."}, {"n": 81, "q": "Why does the speaker say, \"we do use outside suppliers for parts\"?", "opts": ["To recommend a different company", "To justify an increased price", "To explain the source of a problem", "To decline a proposal"], "ans": 2, "ko": "화자가 중반부에 인용문을 언급하면서 자신의 회사가 좋지 못한 금속 부품을 받은 것 같다(Apparently, we received some inferior metal components)고 했다. 이는 문제가 발생한 원인을 설명하는 말이므로 정답은 (C)이다."}, {"n": 82, "q": "What does the speaker say he will do today?", "opts": ["Interview some applicants", "Send a shipment", "Train some staff", "Update a spreadsheet"], "ans": 1, "ko": "화자가 후반부에 오늘 새 금속 부품으로 제작된 파라솔 세트 교체품을 무료로 보내 주겠다(We will send you a replacement set of umbrellas at no cost today, constructed with new metal parts)고 했으므로 정답은 (B)이다."}], "script": [{"sp": "M", "en": "Ms. Stewart, this is Rodrigo Gomez, president of Gomez and Sons. I want to apologize personally for the problems your restaurant experienced using our patio umbrellas. At our company, we pride ourselves on doing everything in-house, from graphic design to production. This gives us greater control over the quality of our products. But we do use outside suppliers for parts. Apparently, we received some inferior metal components. We will send you a replacement set of umbrellas at no cost today, constructed with new metal parts.", "ko": "스튜어트 씨, 저는 고메즈 앤 썬즈의 대표, 로드리고 고메즈입니다. 귀하의 레스토랑에서 저희 테라스용 파라솔을 이용하면서 겪은 문제들에 대해 직접 사과드리고자 합니다. 저희 회사에서는 그래픽 디자인부터 생산까지 모든 것을 회사 내에서 하고 있다는 데 자부심을 가지고 있습니다. 이것은 제품의 품질을 더 잘 통제할 수 있게 해 줍니다. 하지만 부품은 외부 공급업체를 이용합니다. 보아하니, 좋지 못한 금속 부품을 받은 것 같습니다. 저희가 오늘 새 금속 부품으로 제작된 파라솔 세트 교체품을 무료로 보내 드리겠습니다."}]}, {"start": 83, "part": 4, "intro": "", "graphic": false, "speakers": "W-Br", "audio": "Test_04-83-85.mp3", "qs": [{"n": 83, "q": "What type of business is being advertised?", "opts": ["An event planning company", "A financial advising service", "An attorney's office", "A staffing agency"], "ans": 3, "ko": "화자가 초반부에 템프-타임 워크 솔루션즈는 모든 직원 채용 필요를 충족할 수 있는 수백 명의 자격을 갖춘 임시직 근로자를 보유하고 있다(Temp-Time Work Solutions has hundreds of qualified, temporary workers available to meet any of your staffing needs)고 했으므로 정답은 (D)이다."}, {"n": 84, "q": "What aspect of a business does the speaker emphasize?", "opts": ["Its large size", "Its reasonable prices", "Its business hours", "Its long history"], "ans": 0, "ko": "화자가 중반부에 이 지역에서 가장 큰 임시 인력 파견 업체(We are the largest temp agency in the region ~)라고 했으므로 정답은 (A)이다."}, {"n": 85, "q": "How can the listeners receive a discount?", "opts": ["By mentioning an advertisement", "By referring friends", "By paying with a credit card", "By using a coupon"], "ans": 0, "ko": "화자가 후반부에 전화를 걸어 광고를 언급하고 20퍼센트 요금 할인을 받으라(~ mention this ad to get a twenty percent discount off our fee)고 했으므로 정답은 (A)이다."}], "script": [{"sp": "W", "en": "Temp-Time Work Solutions has hundreds of qualified, temporary workers available to meet any of your staffing needs. Please call us to help your business fill open positions. We are the largest temp agency in the region, with branch offices in six locations. Let Temp-Time help you find", "ko": "템프-타임 워크 솔루션즈는 모든 직원 채용 필요를 충족할 수 있는 수백 명의 자격을 갖춘 임시직 근로자를 보유하고 있습니다. 전화 주시면 귀사의 공석을 충원하도록 도와드리겠습니다. 저희는 이 지역에서 가장 큰 임시 인력 파견 업체이며, 여섯 곳에 지사가 있습니다. 템프-타임이 어떤 일이든 완수할 수 있는 적합한 인재를 찾을 수 있도록"}]}, {"start": 86, "part": 4, "intro": "", "graphic": false, "speakers": "M-Au", "audio": "Test_04-86-88.mp3", "qs": [{"n": 86, "q": "What does the speaker mean when he says, \"this is an important opportunity\"?", "opts": ["A new client has an urgent problem.", "Some information is needed from the listeners.", "Some deadlines are flexible.", "The listeners have done a good job."], "ans": 2, "ko": "화자가 청자들의 프로젝트 마감 날짜를 이달 말로 정해 놓았다는 사실을 알고 있지만(I know I've set your project due dates for the end of the month as well, but)이라며 인용문을 언급했고, 콘퍼런스가 중요한 기회이니 마감일을 변경해서라도 참석해야 한다는 뜻이므로 정답은 (C)이다."}, {"n": 87, "q": "What will the speaker's business do next year?", "opts": ["Redesign advertising materials", "Open new locations", "Hire a new vendor", "Implement a security policy"], "ans": 1, "ko": "화자가 중반부에 내년에 두 곳의 새로운 도시에 호텔을 개장할 것(we'll be opening hotels in two new cities next year)이라고 했으므로 정답은 (B)이다."}, {"n": 88, "q": "What will Thilo do next?", "opts": ["Practice his conference presentation", "Provide a construction update", "Summarize some financial data", "Contact a supply vendor"], "ans": 1, "ko": "화자가 후반부에 틸로가 지난주에 공사 현장 두 곳을 방문했고 이제 진행 상황을 보고할 예정(Thilo visited both of those construction sites last week and is now going to give us a progress report)이라고 했으므로 정답은 (B)이다."}], "script": [{"sp": "M", "en": "I've just received details about this year's hospitality conference. It looks like it'll be particularly informative this year. It'll be held at the end of the month. Now, I know I've set your project due dates for the end of the month as well, but this is an important opportunity. The conference will feature an expo of vendors who serve hotel chains, which could be useful given that we'll be opening hotels in two new cities next year! Speaking of which, Thilo visited both of those construction sites last week and is now going to give us a progress report.", "ko": "올해의 접객업 콘퍼런스에 관한 상세 정보를 방금 받았습니다. 올해는 특히 유익할 것으로 보입니다. 이 행사는 이달 말에 개최될 것입니다. 자, 제가 여러분의 프로젝트 마감 날짜도 이달 말로 정해 놓았다는 사실을 알고 있지만, 이는 중요한 기회입니다. 이번 콘퍼런스에는 호텔 체인에 서비스를 제공하는 판매업체들의 박람회가 포함될 텐데, 우리가 내년에 두 곳의 새로운 도시에 호텔을 개장할 예정인 것을 고려하면 유용할 것입니다! 말이 나온 김에, 틸로가 지난주에 그 공사 현장 두 곳을 방문했고, 이제 진행 상황을 보고할 예정입니다."}]}, {"start": 89, "part": 4, "intro": "", "graphic": false, "speakers": "W-Am", "audio": "Test_04-89-91.mp3", "qs": [{"n": 89, "q": "What does the speaker say is new about this year's event?", "opts": ["It takes place outdoors.", "It is sponsored by a major publication.", "It has been sold out for months.", "It is being streamed live."], "ans": 3, "ko": "화자가 초반부에 올해는 처음으로 이 행사를 인터넷에서 라이브로 중계한다(This year, we're streaming this event live over the Internet for the very first time!)고 했으므로 정답은 (D)이다."}, {"n": 90, "q": "Why is Ms. Alabi being recognized?", "opts": ["She is a talented songwriter.", "She invented a musical instrument.", "She started a major record label.", "She supports several charities."], "ans": 2, "ko": "화자가 중반부에 올가 앨러비는 1996년에 I-비트 음반사를 설립했고, 오리지널 사운드트랙 음악을 전 세계의 영화 관람객들에게 전하고자 부단히 노력해 왔다(~ Olga Alabi, founded the I-Beat music label in 1996. She has worked tirelessly to bring original soundtrack music to film audiences around the world)고 했으므로 정답은 (C)이다."}, {"n": 91, "q": "According to the speaker, what will happen after Ms. Alabi receives her award?", "opts": ["Photographs will be taken.", "Dinner will be served.", "Some musicians will perform.", "Some interviews will be held."], "ans": 2, "ko": "화자가 후반부에 앨러비 씨가 상을 받은 후, 그녀의 가장 유명한 고객 중 일부가 공연할 예정(~ after Ms. Alabi receives her award, some of her most famous clients will perform for us)이라고 했으므로 정답은 (C)이다."}], "script": [{"sp": "W", "en": "Welcome to the annual Soundtrack Music Awards show.", "ko": "연례 사운드트랙 음악 시상식에 오신 것을 환영합니다."}, {"sp": "W", "en": "This year, we're streaming this event live over the Internet for the very first time!", "ko": "올해는 처음으로 이 행사를 인터넷에서 라이브로 중계합니다!"}, {"sp": "W", "en": "Tonight's honoree, Olga Alabi, founded the I-Beat music label in 1996.", "ko": "오늘 밤의 수상자인 올가 앨러비는 1996년에 I-비트 음반사를 설립했습니다."}, {"sp": "W", "en": "She has worked tirelessly to bring original soundtrack music to film audiences around the world.", "ko": "그녀는 오리지널 사운드트랙 음악을 전 세계의 영화 관람객들에게 전하고자 부단히 노력해 왔습니다."}, {"sp": "W", "en": "Over the years, she has been responsible for discovering and developing some of today's leading composers.", "ko": "수년간, 그녀는 오늘날 최고의 작곡가들을 발굴하고 개발하는 일을 담당해 왔습니다."}, {"sp": "W", "en": "In fact, after Ms. Alabi receives her award, some of her most famous clients will perform for us.", "ko": "사실, 앨러비 씨가 상을 받은 후, 그녀의 가장 유명한 고객 중 일부가 공연할 예정입니다."}]}, {"start": 92, "part": 4, "intro": "", "graphic": false, "speakers": "M-Cn", "audio": "Test_04-92-94.mp3", "qs": [{"n": 92, "q": "Which department does the speaker most likely work in?", "opts": ["Sales", "Accounting", "Human resources", "Information technology"], "ans": 0, "ko": "화자가 초반부에 팀원들에게 1분기 매출 수치에 대해 논의해 보자(OK, team, let's discuss our first-quarter sales figures)고 했으므로 정답은 (A)이다."}, {"n": 93, "q": "Why does the speaker say, \"those have been popular lately\"?", "opts": ["To express disbelief", "To explain a shortage", "To agree with a proposal", "To make a correction"], "ans": 2, "ko": "화자가 중반부에 대표가 가상 현실 헤드셋을 포함하여 제품 라인을 확장할 것을 제안했다(Our president has proposed expanding the product line to include a virtual reality headset)고 알리면서 인용문을 언급하고 있다. 이는 인기 있는 제품이기 때문에 대표가 제안한 대로 하는 것이 좋겠다는 의미를 나타내는 말이므로 정답은 (C)이다."}, {"n": 94, "q": "What will the listeners do next?", "opts": ["Take a lunch break", "Ask questions about a policy", "Read a report", "View a demonstration"], "ans": 3, "ko": "화자가 후반부에 다음 안건으로는, 소비자 구매 경향을 파악하기 위해 사용할 새 소프트웨어를 라야가 시연해 줄 것(Next on the agenda, Raya will be demonstrating the new software we'll be using to track consumer purchasing trends)이라고 했으므로 정답은 (D)이다."}], "script": [{"sp": "M", "en": "OK, team, let's discuss our first-quarter sales figures.", "ko": "좋아요, 팀원 여러분, 1분기 매출 수치에 대해 논의해 봅시다."}, {"sp": "M", "en": "Unfortunately, retail sales of our smartwatches and other products have continued to fall.", "ko": "안타깝게도, 스마트워치와 기타 제품들의 소매 판매가 계속 감소하고 있습니다."}, {"sp": "M", "en": "Our president has proposed expanding the product line to include a virtual reality headset.", "ko": "대표님은 가상 현실 헤드셋을 포함하여 제품 라인을 확장할 것을 제안했습니다."}, {"sp": "M", "en": "And those have been popular lately.", "ko": "그리고 그것들이 요즘 인기 있습니다."}, {"sp": "M", "en": "You can expect a lot more information at a future meeting.", "ko": "여러분은 향후 회의에서 더 많은 정보를 기대할 수 있습니다."}, {"sp": "M", "en": "Next on the agenda, Raya will be demonstrating the new software we'll be using to track consumer purchasing trends.", "ko": "다음 안건으로는, 소비자 구매 경향을 파악하기 위해 사용할 새 소프트웨어를 라야가 시연해 줄 것입니다."}]}, {"start": 95, "part": 4, "intro": "", "graphic": true, "speakers": "M-Au", "audio": "Test_04-95-97.mp3", "qs": [{"n": 95, "q": "Where are the listeners?", "opts": ["At a farm", "At a factory", "At a museum", "At a stadium"], "ans": 3, "ko": "화자가 초반부에 오늘의 견학을 시작한다(we'll begin today's tour)고 했고, 이어서 축구 팬(a football fan)과 이 정도 규모의 현대적인 스포츠 시설(a modern sports facility of this size)을 언급한 것에서 경기장에 있음을 알 수 있다. 따라서 정답은 (D)이다."}, {"n": 96, "q": "Look at the graphic. When is the tour taking place?", "opts": ["On Monday", "On Tuesday", "On Wednesday", "On Thursday"], "ans": 0, "ko": "화자가 중반부에 오늘의 예보는 햇빛과 구름이 섞인 날씨를 보여 준다(~ today's forecast shows a mix of sun and clouds, ~)고 했고, 일기 예보에서 해와 구름이 함께 있는 날은 월요일이므로 정답은 (A)이다."}, {"n": 97, "q": "What will happen at the end of the tour?", "opts": ["Pictures will be taken.", "Food will be served.", "Gifts will be given out.", "A shuttle bus will arrive."], "ans": 3, "ko": "화자가 후반부에 견학이 끝나면 셔틀버스가 와서 주차장으로 다시 데려다 줄 것(~ a shuttle bus will meet us at the end of the tour to bring us all back to the parking lot)이라고 했으므로 정답은 (D)이다."}], "script": [{"sp": "M", "en": "Please follow me, and we'll begin today's tour.", "ko": "저를 따라오시면, 오늘의 견학을 시작하겠습니다."}, {"sp": "M", "en": "Now, I know not everyone who takes this all-access tour is a football fan.", "ko": "자, 모든 구역에 출입할 수 있는 이번 견학에 참여하는 모든 분들이 축구 팬은 아니라는 것을 알고 있습니다."}, {"sp": "M", "en": "Many of our visitors are just curious about how a modern sports facility of this size operates.", "ko": "방문객 중 많은 사람들이 단지 이 정도 규모의 현대적인 스포츠 시설이 어떻게 운영되는지 궁금해합니다."}, {"sp": "M", "en": "Well, you'll get to see that and much more.", "ko": "음, 여러분은 그 이상의 것을 보실 것입니다."}, {"sp": "M", "en": "And fortunately for us, today's forecast shows a mix of sun and clouds, with no rain.", "ko": "그리고 다행스럽게도, 오늘의 예보는 비 없이 햇빛과 구름이 섞인 날씨를 보여줍니다."}, {"sp": "M", "en": "That's just the right combination for spending some time outside on the field comfortably.", "ko": "야외 경기장에서 편하게 시간을 보내기에 딱 좋은 조합입니다."}, {"sp": "M", "en": "Also, as a heads-up, a shuttle bus will meet us at the end of the tour to bring us all back to the parking lot.", "ko": "또한, 미리 알려 드리자면, 견학이 끝나면 셔틀버스가 와서 주차장으로 다시 모셔다 드릴 것입니다."}], "gimg": "ets_t4_g95.jpg"}, {"start": 98, "part": 4, "intro": "", "graphic": true, "speakers": "W-Br", "audio": "Test_04-98-100.mp3", "qs": [{"n": 98, "q": "What type of event is being held tonight?", "opts": ["A grand opening", "A company anniversary", "A retirement party", "A wedding celebration"], "ans": 2, "ko": "화자가 초반부에 오늘 밤 큰 행사를 개최한다며 잴튼 주식회사에서 오랫동안 근무한 직원의 은퇴를 기념하는 저녁 만찬(It's a dinner party to celebrate the retirement of a longtime employee of Jalton Incorporated)이라고 했으므로 정답은 (C)이다."}, {"n": 99, "q": "Look at the graphic. Which assignment will Kota be responsible for?", "opts": ["Organizing the food-serving station", "Hanging decorations", "Creating flower arrangements", "Setting up tables and chairs"], "ans": 1, "ko": "화자가 중반부에 아만다가 올 수 없어서, 코타가 대신해 아만다에게 배정된 업무를 맡을 것(Amanda couldn't make it, so Kota's covering for her and will take Amanda's assignment)이라고 했고, 업무 배정표에서 아만다의 업무가 장식물 걸기라는 것을 알 수 있으므로 정답은 (B)이다."}, {"n": 100, "q": "What does the speaker say she has to do at noon?", "opts": ["Go to the airport", "Pick up some tablecloths", "Cook a meal", "Attend a meeting"], "ans": 3, "ko": "화자가 후반부에 정오에 잠재 고객과 회의가 있다(I have a meeting with a potential client at noon ~)고 했으므로 정답은 (D)이다."}], "script": [{"sp": "W", "en": "As you all know, we're hosting a large event tonight.", "ko": "모두 아시다시피, 오늘 밤 큰 행사를 개최합니다."}, {"sp": "W", "en": "It's a dinner party to celebrate the retirement of a longtime employee of Jalton Incorporated.", "ko": "잴튼 주식회사에서 오랫동안 근무한 직원의 은퇴를 기념하는 저녁 만찬입니다."}, {"sp": "W", "en": "The chefs are already prepping dinner, and I need you all to set up the ballroom.", "ko": "요리사들이 이미 저녁 식사를 준비하고 있으니, 여러분은 모두 연회장을 준비해 주시기 바랍니다."}, {"sp": "W", "en": "Here's the assignment list. There's just one change.", "ko": "여기 업무 배정표가 있습니다. 단 한 가지 변동 사항이 있습니다."}, {"sp": "W", "en": "Amanda couldn't make it, so Kota's covering for her and will take Amanda's assignment.", "ko": "아만다가 올 수 없어서, 코타가 대신해 아만다에게 배정된 업무를 맡을 것입니다."}, {"sp": "W", "en": "Now, I have a meeting with a potential client at noon, but otherwise, I'll be available all day if anything comes up.", "ko": "자, 저는 정오에 잠재 고객과 회의가 있지만, 그 외에는 무슨 일이 생기면 하루 종일 시간이 있습니다."}], "gimg": "ets_t4_g98.jpg"}]};
